#[unsafe(no_mangle)]
pub fn rust_main() -> ! {
    clear_bss();

    #[cfg(target_arch = "loongarch64")]
    {
        arch::enable_boot_paging();
        unsafe {
            arch::jump_to_high_half(rust_main_high as usize);
        }
    }

    #[cfg(target_arch = "riscv64")]
    rust_main_high()
}

fn rust_main_high() -> ! {
    #[cfg(target_arch = "loongarch64")]
    arch::enable_kernel_extensions();

    #[cfg(target_arch = "loongarch64")]
    timer::init_clock_freq();

    trap::init();
    mm::init();
    net::init();
    task::add_initproc();
    trap::enable_timer_interrupt();
    timer::set_next_ti_trigger();

    #[cfg(feature = "verbose_boot")]
    loader::list_apps();
    task::run_tasks();

    panic!("unreachable!");
}

/// 启动早期清零 BSS。
fn clear_bss() {
    unsafe extern "C" {
        unsafe fn sbss();
        unsafe fn ebss();
    }

    #[cfg(target_arch = "loongarch64")]
    unsafe {
        let mut cur = sbss as usize;
        let end = ebss as usize;

        while cur.wrapping_add(core::mem::size_of::<usize>()) <= end {
            core::arch::asm!(
                "st.d $zero, {addr}, 0",
                addr = in(reg) cur,
                options(nostack, preserves_flags)
            );
            cur = cur.wrapping_add(core::mem::size_of::<usize>());
        }
        while cur < end {
            core::arch::asm!(
                "st.b $zero, {addr}, 0",
                addr = in(reg) cur,
                options(nostack, preserves_flags)
            );
            cur = cur.wrapping_add(1);
        }
    }

    #[cfg(target_arch = "riscv64")]
    (sbss as *const () as usize..ebss as *const () as usize)
        .for_each(|a| unsafe { (a as *mut u8).write_volatile(0) });
}

