    file: Arc<dyn FileOp>,
    offset: usize,
    _len: usize,
    map_len: usize,
    shared: bool,
) -> SysResult<MmapBacking<'static>> {
    let file_len = file.get_stat()?.size.saturating_sub(offset).min(map_len);
    if shared {
        Ok(MmapBacking::SharedFile {
            file,
            offset,
            len: file_len,
        })
    } else {
        Ok(MmapBacking::PrivateFile {
            file,
            offset,
            len: file_len,
        })
    }
}

