            let size = inode.stat(&abs_path).map(|stat| stat.size).unwrap_or(0);
            if size > pc.len() {
                pc.resize(size);
            }
        }
        Self {
            inode,
            inner: Mutex::new(FileInner {
                offset,
                path,
                flags,
                dirent_cache: None,
                page_cache,
                write_back,
                tmpfile_meta: None,
                atime_override: None,
                mtime_override: None,
                ctime_override: None,
