pub const PAGE_SIZE_BITS: usize = 12;
/// 动态链接器（ld-linux）的加载基址偏移
pub const DL_INTERP_OFFSET: usize = 0x30_0000_0000;
/// times() 系统调用的时钟滴答频率（Linux ABI 标准值 100Hz）
pub const CLK_TCK: usize = 100;

/// 用户态 sigreturn 跳板页的虚拟地址。
/// 该页在所有用户进程的地址空间中映射到同一位置。
///
/// Sv39 低半区最高一页的 end VPN 会跨到另一半区，和当前 VPNRange 的同半区
/// 检查冲突，因此这里保留最高一页不用。
pub const TRAMPOLINE: usize = 0x0000_003f_ffff_e000;

// LoongArch QEMU virt 机器板级配置

// LoongArch QEMU virt 机器时钟频率。
//
// 这组值刻意拆成三类：
// - HARDWARE_CLOCK_FREQ：真实硬件计数器频率，用于 timer interrupt 和 timeout。
// - USER_CLOCK_FREQ：用户可见时间频率，用于 gettimeofday/clock_gettime，可为 bench 调整。
// - ACCOUNTING_CLOCK_FREQ：times()/getrusage() 这类 CPU 时间记账的换算频率。
//
// 当前 QEMU virt 的 rdtime.d/CPUCFG 通常对应 100MHz。USER_CLOCK_FREQ 保持较低值
// 是为了保留 bench-facing wall clock 的可调空间；不要再把它用于硬件 timer 编程。
pub const HARDWARE_CLOCK_FREQ: usize = 100_000_000;
pub const USER_CLOCK_FREQ: usize = 100_000_000;
pub const ACCOUNTING_CLOCK_FREQ: usize = HARDWARE_CLOCK_FREQ;
// QEMU loongarch64 virt with `-m 128M` maps RAM in low memory.
pub const MEMORY_START: usize = 0;
pub const MEMORY_END: usize = 0x1000_0000;

pub const PCI_ECAM_BASE: usize = 0x2000_0000;
pub const PCI_ECAM_SIZE: usize = 0x1000_0000;
pub const PCI_MMIO_BASE: usize = 0x4000_0000;
pub const PCI_MMIO_SIZE: usize = 0x1000_0000;
pub const GED_REG_BASE: usize = 0x100e_0000;
pub const GED_REG_SIZE: usize = 0x1000;

// MMIO 设备地址区间 (QEMU loongarch64 virt 平台)
pub const MMIO: &[(usize, usize)] = &[
    (0x1000_1000, 0x00_1000),       // Virtio Block
    (GED_REG_BASE, GED_REG_SIZE),   // ACPI GED power/reset registers
    (0x1fe0_0000, 0x00_1000),       // UART
    (0x0010_0000, 0x00_2000),       // VIRT_TEST/RTC
    (PCI_ECAM_BASE, PCI_ECAM_SIZE), // PCIe ECAM
    (PCI_MMIO_BASE, PCI_MMIO_SIZE), // PCI BAR memory window
];

OUTPUT_ARCH(riscv)
ENTRY(_start)
BASE_ADDRESS = 0xffffffc080200000;
LOAD_ADDRESS = 0x80200000;
KERNEL_OFFSET = BASE_ADDRESS - LOAD_ADDRESS;

SECTIONS
{
    . = BASE_ADDRESS;
    skernel = .;

    stext = .;
    .text : AT(ADDR(.text) - KERNEL_OFFSET) {
        *(.text.entry)
        . = ALIGN(4K);
        *(.text .text.*)
    }

    . = ALIGN(4K);
    etext = .;
    srodata = .;
    .rodata : AT(ADDR(.rodata) - KERNEL_OFFSET) {
        *(.rodata .rodata.*)
        *(.srodata .srodata.*)
    }

    . = ALIGN(4K);
    erodata = .;
    sdata = .;
    .data : AT(ADDR(.data) - KERNEL_OFFSET) {
        *(.data .data.*)
        *(.sdata .sdata.*)
    }

    . = ALIGN(4K);
    edata = .;
    sbss_with_stack = .;
    .bss : AT(ADDR(.bss) - KERNEL_OFFSET) {
        *(.bss.stack)
        sbss = .;
        *(.bss .bss.*)
        *(.sbss .sbss.*)
    }

    . = ALIGN(4K);
    ebss = .;
    ekernel = .;

    /DISCARD/ : {
        *(.eh_frame)
        *(.eh_frame_hdr)
    }
}

OUTPUT_ARCH(loongarch)
ENTRY(_start_phys)

PHYS_ADDR = 0x00200000;
BASE_ADDRESS = 0xffffffc000200000;
KERNEL_OFFSET = BASE_ADDRESS - PHYS_ADDR;
_start_phys = PHYS_ADDR;

SECTIONS
{
    . = BASE_ADDRESS;
    skernel = .;

    stext = .;
    .text : AT(ADDR(.text) - KERNEL_OFFSET) {
        KEEP(*(.text.entry))
        . = ALIGN(4K);
        srfill = .;
        KEEP(*(.text.__rfill))
        . = ALIGN(4K);
        erfill = .;
        *(.text .text.*)
    }

    . = ALIGN(4K);
    etext = .;
    srodata = .;
    .rodata : AT(ADDR(.rodata) - KERNEL_OFFSET) {
        *(.rodata .rodata.*)
        *(.srodata .srodata.*)
    }

    . = ALIGN(4K);
    erodata = .;
    sdata = .;
    .data : AT(ADDR(.data) - KERNEL_OFFSET) {
        *(.data .data.*)
        *(.sdata .sdata.*)
    }

    . = ALIGN(4K);
    edata = .;
    sbss_with_stack = .;
    .bss : AT(ADDR(.bss) - KERNEL_OFFSET) {
        *(.bss.stack)
        sbss = .;
        *(.bss .bss.*)
        *(.sbss .sbss.*)
    }

    . = ALIGN(4K);
    ebss = .;
    ekernel = .;

    /DISCARD/ : {
        *(.eh_frame)
        *(.eh_frame_hdr)
    }
}
